              {recipeData.category}

{recipeData.title}



{recipeData.prepTime} PREP

{recipeData.cookTime} CUISSON

{recipeData.difficulty}





        {/* CONTENU PRINCIPAL */}





            {/* COLONNE GAUCHE */}




                {/* Calculateur Portions */}





                    Parts



                     updateServings(-1)} className="text-white hover:text-[#D4AF37] h-8 w-8 rounded-full">


                    {servings}
                     updateServings(1)} className="text-white hover:text-[#D4AF37] h-8 w-8 rounded-full">





                {/* Liste Ingrédients */}

Ingrédients

                  {ingredients.map((ing, i) => (


                      {ing.name}

                        {calculateQuantity(ing.amount, recipeData.baseServings)} {ing.unit}


                  ))}




            {/* COLONNE DROITE */}




                {steps.map((step, i) => (



{i+1}



{step.title}

{step.text}


                ))}


