const PaletBreton = () => {
  const recipeData = {
    category: "PÂTISSERIE • BISCUITS", // 👈 CORRIGÉ (C'est un biscuit sablé)
    title: "Palet Breton",
    prepTime: "20 MIN",
    cookTime: "15 MIN",
    difficulty: "FACILE",
    description: "Le palet breton est un biscuit sablé emblématique, riche en beurre demi-sel et friable à souhait. Une base parfaite aussi pour des entremets.",
    image: "https://www.tendances-food.fr/wp-content/uploads/2022/11/palets-bretons.jpg",
    baseServings: 10,
  };

  const [servings, setServings] = useState(recipeData.baseServings);

  const updateServings = (change) => {
    const newServings = servings + change;
    if (newServings >= 1) setServings(newServings);
  };

  // 🧮 FONCTION DE CALCUL STANDARDISÉE
  const calculateQuantity = (amount, base) => {
    if (!amount) return "";
    const numAmount = parseFloat(amount);
    if (isNaN(numAmount)) return amount;
    const scaled = (numAmount * servings) / base;
    return Number.isInteger(scaled) ? scaled : scaled.toFixed(1).replace('.0', '');
  };

  const ingredients = [
    { name: 'Beurre demi-sel', amount: 160, unit: 'g' },
    { name: 'Sucre glace', amount: 120, unit: 'g' },
    { name: 'Jaunes d\'oeufs', amount: 40, unit: 'g' },
    { name: 'Farine courante', amount: 200, unit: 'g' },
    { name: 'Levure Chimique', amount: 6, unit: 'g' },
    { name: 'Vanille liquide', amount: 5, unit: 'g' }
  ];

  const steps = [
    {
      title: "RÉALISATION DE LA PÂTE",
      text: "Dans la cuve du batteur, crémer le beurre pommade avec le sucre glace. Ajouter les jaunes tempérés et émulsionner. Ajouter la vanille. Enfin, incorporer délicatement la farine tamisée avec la levure chimique. Fraser sans corser la pâte."
    },
    {
      title: "REPOS AU FRAIS",
      text: "Filmer la pâte au contact et la placer au frais (réfrigérateur) pendant au moins 2 heures pour qu'elle raffermisse."
    },
    {
      title: "DÉTAILLAGE",
      text: "Beurrer des cercles de 6cm de diamètre. Étaler la pâte entre deux règles à environ 5mm ou 1cm d'épaisseur selon le résultat souhaité. Détailler des disques à l'emporte-pièce et les placer dans les cercles beurrés."
    },
    {
      title: "CUISSON",
      text: "Cuire au four à sol ou ventilé à 200°C pendant environ 15 minutes. Les palets doivent être bien dorés. Démouler sur plaque et laisser refroidir."
    }
  ];

  // --- GOOGLE SEO (JSON-LD) ---
  const structuredData = {
    "@context": "https://schema.org/",
    "@type": "Recipe",
    "name": recipeData.title,
    "image": [recipeData.image],
    "description": recipeData.description,
    "author": { "@type": "Person", "name": "Pastrypower" },
    "prepTime": "PT20M",
    "cookTime": "PT15M",
    "recipeYield": `${servings} palets`,
    "recipeIngredient": ingredients.map(ing => `${calculateQuantity(ing.amount, recipeData.baseServings)} ${ing.unit} ${ing.name}`),
    "recipeInstructions": steps.map((step, index) => ({
      "@type": "HowToStep",
      "position": index + 1,
      "name": step.title,
      "text": step.text
    }))
  };

  return (
    <>

        {recipeData.title} - Pastrypower


          {JSON.stringify(structuredData)}





        {/* HEADER IMAGE */}









              {recipeData.category}

{recipeData.title}



{recipeData.prepTime} PREP

{recipeData.cookTime} CUISSON

{recipeData.difficulty}





        {/* CONTENU PRINCIPAL */}





            {/* COLONNE GAUCHE */}




                {/* Calculateur Portions */}





                    Palets



                     updateServings(-1)} className="text-white hover:text-[#D4AF37] h-8 w-8 rounded-full">


                    {servings}
                     updateServings(1)} className="text-white hover:text-[#D4AF37] h-8 w-8 rounded-full">





                {/* Liste Ingrédients */}

Ingrédients

                  {ingredients.map((ing, i) => (


                      {ing.name}

                        {calculateQuantity(ing.amount, recipeData.baseServings)} {ing.unit}


                  ))}




            {/* COLONNE DROITE */}




                {steps.map((step, i) => (



{i+1}



{step.title}

{step.text}


                ))}


              {/* Onglets Conseils / Chef / Ustensiles */}


                  Conseils
                  Le Mot du Chef
                  Ustensiles











Technique de cuisson


Il est impératif de cuire les palets bretons dans des cercles non graissés. Sans cela, la pâte s'étalera en galette plate à cause de la levure et du beurre.

Le beurre demi-sel est la signature du palet breton. Ne le remplacez pas par du beurre doux.

Ne travaillez pas trop la pâte après l'ajout de la farine pour éviter qu'elle ne devienne élastique.












L'avis du Chef


                          "Ce qui fait un grand palet breton, c'est ce contraste entre la friabilité extrême du sablé et la pointe de sel qui vient taquiner le palais en fin de bouche. C'est addictif."












Matériel recommandé



Cercles inox (6cm)


Plaque de cuisson


Batteur (feuille)


Rouleau à pâtisserie










    </>
  );
};
export default PaletBreton;

import React, { useState } from 'react';
import { Helmet } from 'react-helmet';
import { motion } from 'framer-motion';
import { Clock, ChefHat, Minus, Plus, ArrowLeft, Lightbulb, Quote } from 'lucide-react';
import { Link } from 'react-router-dom';
import { Button } from "@/components/ui/button";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";

const ParisBrest = () => {
  const baseServings = 6; // Nombre de personnes
  const [servings, setServings] = useState(baseServings);

  const recipeData = {
    category: "PÂTISSERIE • CLASSIQUES",
    title: "Paris-Brest",
    prepTime: "1H 30",
    cookTime: "40 MIN",
    difficulty: "MOYEN",
    description: "Créé en 1910 pour la course cycliste, ce gâteau en forme de roue associe pâte à choux croustillante, amandes effilées et une généreuse crème mousseline au praliné.",
    image: "https://www.sunny-delices.fr/wp-content/uploads/2021/02/paris-brest-sans-gluten-individuel.jpg",
  };

  const ingredients = [
    { name: 'Pâte à choux', amount: 300, unit: 'g' },
    { name: 'Lait entier', amount: 500, unit: 'ml' },
    { name: 'Sucre semoule', amount: 100, unit: 'g' },
    { name: 'Jaunes d\'oeufs', amount: 80, unit: 'g' },
    { name: 'Poudre à crème', amount: 50, unit: 'g' },
