  ];

  const steps = [
    {
      title: "Cuisson de la couronne",
      text: "Sur une plaque, dressez un cercle de pâte à choux de 20cm de diamètre. Dressez un second cercle collé à l'intérieur du premier, puis un troisième par-dessus à cheval sur les deux autres. Parsemez généreusement d'amandes effilées. Cuire 35-40 min à 170°C. Ne pas ouvrir le four."
    },
    {
      title: "Crème pâtissière de base",
      text: "Faites bouillir le lait. Fouettez jaunes, sucre et poudre à crème. Versez le lait dessus, reversez en casserole et cuire 2 min à ébullition. Incorporez la moitié du beurre (125g) chaud. Filmez au contact et laissez refroidir à température ambiante."
    },
    {
      title: "Crème mousseline praliné",
      text: "Fouettez le reste du beurre pommade (125g) avec le praliné jusqu'à ce qu'il soit mousseux. Incorporez petit à petit la crème pâtissière lissée (elles doivent être à la même température). Fouettez pour aérer la mousseline."
    },
    {
      title: "Montage",
      text: "Coupez la couronne refroidie en deux horizontalement. Pochez la mousseline sur la base avec une douille cannelée en faisant de belles rosaces."
    },
    {
      title: "Finition",
      text: "Posez le chapeau de la couronne délicatement. Saupoudrez de sucre glace. Réservez au frais mais sortez-le 15 min avant dégustation."
    }
  ];

