const Speculoos = () => {
  const recipeData = {
    category: "PÂTISSERIE • PETITS FOURS SECS",
    title: "Spéculoos",
    prepTime: "20 MIN",
    cookTime: "15 MIN",
    difficulty: "FACILE",
